VALUES
  ('colonel-d0d1b9a2-moex-00038', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '試以下列資料運用毛利法推算期末存貨： 期初存貨 $ 400,000 本期進貨淨額 5,000,000 本期銷貨淨額 6,000,000 估計毛利率 20%', '["$600,000", "$1,200,000", "$2,400,000", "$4,800,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00039', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司X3 年全年普通股發行流通在外2,000,000 股。甲公司另於X1 年1 月2日發行10年期5,000張面值$1,000，10%的可轉換公司債，每張公司 債可轉換 15 股普通股，二年後 X3 年起會提高到每張可轉換公司債可轉 換 18 股普通股。該可轉換公司債每年付利息一次，並且，該可轉換公司 債負債部分的利息費用為每年$400,000，自X1年至X3年並無公司債轉換 為普通股，X3年度淨利為$8,000,000，所得稅率為30%，試問（答案四捨 五入至小數點後二位）：', '["該公司X3年度稀釋每股盈餘為$3.96", "該公司X3年度稀釋每股盈餘為$4.00", "該公司X3年度稀釋每股盈餘為$4.02", "該公司X3年度稀釋每股盈餘為$4.06"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00040', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司在 X1 年 1 月 1 日發行 2,500 張可轉換公司債。該債券為 4 年期， 票面利率 6%，每張以面額$1,000 發行，自發行債券所收得現金為 $2,500,000。每年於 12 月 31 日付息一次。每張債券可轉換 200 股普通股 ，每股面額$1。類似的不可轉換債券的市場利率為 9%，經計算甲公司可 轉換債券負債部分X1年1月1日的現值為$2,257,033，X2年12月31日 全數轉換。試作X2年12月31日可轉換公司債轉換為普通股的分錄：', '["應付公司債 2,500,000 股本－普通股 500,000 股本溢價－普通股 2,000,000", "資本公積-認股權 242,967 應付公司債 2,500,000 應付公司債折價 242,967 股本－普通股 500,000 股本溢價－普通股 2,000,000", "資本公積－認股權 242,967 應付公司債 2,500,000 應付公司債折價 131,919 股本－普通股 500,000 股本溢價－普通股 2,111,048", "只需附註揭露，不必作分錄 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00041', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司在X1年開始營運，並對其賣出足球產品提供一年的售後服務保證。 甲公司估計X1年賣出的300,000個產品中，會被送回修理的個數有5,000 個，修理成本每個$6。X1年已被送回修理的產品有4,000個，產生修理成 本$24,000。產品的 X1 年保固政策相關交易對甲公司 X1 年會計報表有何 影響？', '["損益表淨利不變，資產負債表的負債增加", "損益表淨利減少，資產負債表的負債增加", "損益表淨利減少，資產負債表的負債不變", "損益表淨利減少，資產負債表的負債減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00042', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司最近四年度有關應收帳款 X1 年、X2 年、X3 年和 X4 年期末應收 帳款$28,000、$64,000、$104,000 和$99,000，甲公司採用應收帳款百分比 法估計備抵損失-應收帳款(備抵壞帳科目)，該公司各年底之備抵損失-應 收帳款估計為期末應收帳款餘額之10%，但X4年底結帳前發現錯誤：X2 年應轉銷收不回之應收帳款$12,000 漏未沖銷。該錯誤對各年度淨利之影 響何者正確？', '["X4年淨利高估$12,000", "X4年淨利高估$10,800", "X2年淨利高估$12,000", "X2年淨利高估$10,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00043', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年初開業，一向採「先進先出法」作為成本流動假設，報稅亦採 「先進先出法」。該公司擬自X3年1月1日改採「加權平均法」，不同方 法各年銷貨成本如下表，X3年的銷貨收入為$180,000，營業費用$40,000， 所得稅稅率為17%。試問此存貨方法改變相關會計紀錄何者正確？ 年度 先進先出法 加權平均法 X1 $ 74,000 $67,000 X2 90,000 83,000 X3 108,000 96,000', '["此為會計政策變動，X3年1月1日需認列追溯適用及追溯重編影響數， 分錄需借：存貨$11,620", "此為會計估計變動，不需追溯適用或追溯重編", "此為會計政策變動，X3年1月1日需認列追溯適用及追溯重編影響數， X3年1月1日分錄需借：存貨增加$14,000", "此為會計政策變動，X3年1月1日需認列追溯適用及追溯重編影響數， X3年1月1日分錄需借：存貨增加$26,000 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00044', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X1 年 1 月 2 日以$942,919 購入乙公司發行之面額$1,000,000 公司 債做為「透過其他綜合損益按公允價值衡量之金融資產」，期末需依照市 價進行「透過其他綜合損益按公允價值衡量之金融資產評價調整」，按照 該票面利率3%，有效利率5.1%，3 年期，每年12 月31 日付息所編製的 折價攤銷表如下。X1 年12 月31 日該公司債市價為$970,000，甲公司X1 年會計報表表達「透過其他綜合損益按公允價值衡量之金融資產」帳面金 額和未實現利益何者正確？ 日期 借：現金 借：金融資產 貸：利息收入 帳面金額 X1/1/2 942,919 X1/12/31 30,000 18,089 48,089 961,008 X2/12/31 30,000 19,011 49,011 980,019 X3/12/31 30,000 19,981 49,981 1,000,000', '["資產負債表的資產： 「透過其他綜合損益按公允價值衡量之金融資產-公司債」帳面金額 $961,008 損益表的未實現利益： $8,992", "資產負債表的資產： 「透過其他綜合損益按公允價值衡量之金融資產-公司債」帳面金額 $961,008 資產負債表的股東權益項下「其他權益-金融資產未實現損益」 $8,992", "資產負債表的資產： 「透過其他綜合損益按公允價值衡量之金融資產-公司債」 $961,008 「透過其他綜合損益按公允價值衡量之金融資產評價調整」 8,992 帳面金額 $970,000 損益表的未實現利益： $8,992", "資產負債表的資產： 「透過其他綜合損益按公允價值衡量之金融資產-公司債」 $961,008 「透過其他綜合損益按公允價值衡量之金融資產評價調整」 8,992 帳面金額 $970,000 資產負債表的股東權益項下「其他權益-金融資產未實現損益」 $8,992 30650"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00045', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', 'X1 年 1 月 2 日乙公司以$2,162,218 發行 2,000 張公司債，面額$1,000，5 年期，每年6月30日及12月31日付息，票面利率10%，市場利率8%， 試問乙公司X1年1月2日的分錄為何？', '["現金 2,162,218 應付公司債 2,000,000 公司債溢價 162,218", "按攤銷後成本衡量之金融資產-公司債 2,162,218 現金 2,162,218", "現金 2,000,000 應付公司債 2,000,000", "按攤銷後成本衡量之金融資產-公司債 2,000,000 現金 2,000,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00046', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司存貨管理採用定期盤存制，X1年3月1日進貨$4,000，購買條件2/10, n/30，甲公司在X1 年3 月2 日支付3 月1 日進貨時的運費$150，甲公司3 月2日時發現商品不能正常運作，退回$200之商品，甲公司在X1年3月9 日支付剩餘積欠的貨款，試問甲公司購買這批貨的進貨成本為何？', '["$3,870", "$3,874", "$3,950", "$4,024"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00047', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-112-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '發放股票股利和股票分割對於股票面額、保留盈餘及股東權益的影響為何？', '["發放股票股利：每股面值增加，保留盈餘增加，股東權益增加 股票分割：每股面值增加，保留盈餘增加，股東權益增加", "發放股票股利：每股面值不變，保留盈餘減少，股東權益不變 股票分割：每股面值減少，保留盈餘不變，股東權益不變", "發放股票股利：每股面值減少，保留盈餘不變，股東權益不變 股票分割：每股面值不變，保留盈餘減少，股東權益不變", "發放股票股利：每股面值減少，保留盈餘減少，股東權益減少 股票分割：每股面值減少，保留盈餘減少，股東權益減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL)
